  1→import { useInfiniteQuery } from '@tanstack/react-query';
  2→import './sidebarOpinions.css'
  3→import { getOpinions } from '../../../API/Api';
  4→import { useNavigate } from 'react-router-dom';
  5→import { handleClickProfile } from '../../../helpers/handleClicks';
  6→import { useAuth } from '../../Context/useAuth';
  7→import { BarLoader, MoonLoader } from 'react-spinners';
  8→import VerifiedBadge from '../Badge/VerifiedBadge';
  9→import formatPostDate from '../../../helpers/formatDateString';
 10→import MentionText from '../mentions/MentionText';
 11→
 12→const SidebarOpinions = ({openEditor}) =>{
 13→    const {user, session, openAuthModal} = useAuth();
 14→
 15→    const handleOpenEditor = () =>{
 16→        if(!session) return openAuthModal();
 17→        openEditor();
 18→    }
 19→    const navigate = useNavigate();
 20→
 21→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
 22→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
 23→        if(!session){
 24→            e.stopPropagation();
 25→            return openAuthModal();
 26→        }
 27→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
 28→    };
 29→
 30→    const {data, isLoading, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 31→        queryKey: ['getOpinions'],
 32→        queryFn: ({pageParam = null}) => getOpinions(pageParam, 5),
 33→        getNextPageParam: (lastPage) =>{
 34→            if(lastPage?.hasMore){
 35→                const lastOpinion = lastPage?.data[lastPage?.data?.length - 1];
 36→                return lastOpinion.id;
 37→            } else {
 38→                return undefined
 39→            }
 40→        },
 41→        refetchOnWindowFocus: false,
 42→        staleTime: 1000 * 60 * 5,
 43→    });
 44→
 45→    const handleClickSeeMore = () =>{
 46→        if(!isLoading && !isFetchingNextPage){
 47→            fetchNextPage();;
 48→        }
 49→
 50→    }
 51→
 52→    const handleClickContent = (e, opinionId, userId) =>{
 53→        e.stopPropagation();
 54→        if(!session) return openAuthModal();
 55→        navigate('/home/opinionsViewer', {
 56→            state: {
 57→                opinionId: opinionId,
 58→                userId: userId
 59→            }
 60→        })
 61→    }
 62→
 63→    const opinions = data?.pages.flatMap((page) => page.data) || [];
 64→
 65→    if(opinions.length === 0){
 66→        return(
 67→            <div className='side-bar-opinions-parent-container'>
 68→                <div className='signal-container'>
 69→                    <p className='signal-header'>"Share what you believe. This is a free-speech space."</p>
 70→                    <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
 71→                        Write opinions
 72→                    </button>
 73→                </div>
 74→                <div className='latest-opinions-container'>
 75→                    <div className='latest-opinions-header'>
 76→                        Latest opinions
 77→                    </div>
 78→                    <div className='sidebar-opinions-cards-container'>
 79→                        No opinions availabe
 80→                    </div>
 81→                </div>
 82→            </div>
 83→        )
 84→    }
 85→    if(isLoading){
 86→        return(
 87→            <div className='side-bar-opinions-parent-container'>
 88→                <div className='opinions-loading-container'>
 89→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
 90→                </div>
 91→            </div>
 92→        )
 93→    }
 94→    return(
 95→        <>
 96→        <div className="side-bar-opinions-parent-container">
 97→            <div className='signal-container'>
 98→                <p className='signal-header'>"Share what you believe. This is a free-speech space."</p>
 99→                <button onClick={() => handleOpenEditor()} className='write-opinions-bttn'>
100→                    Write opinions
101→                </button>
102→            </div>
103→
104→            <div className='latest-opinions-container'>
105→                <div className='latest-opinions-header'>
106→                    Latest opinions
107→                </div>
108→                <div className='sidebar-opinions-cards-container'>
109→                    {opinions.map((opinionsData) => (
110→                        <div key={opinionsData.id} className="so-card-wrapper">
111→                            <div className="so-card">
112→                                <div className="so-card-content">
113→                                    <div className="so-header-row">
114→                                        <div className={`so-avatar-outer ${opinionsData.users.badge === 'legend' ? 'avatar-ring-legend' : opinionsData.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
115→                                            <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-avatar" src={opinionsData.users.image_url || "../../assets/profile.jpg"} alt={`${opinionsData?.users?.name || "User"} profile picture`} />
116→                                        </div>
117→                                        <span onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, opinionsData.user_id)} className="so-username">{opinionsData.users.name}</span>
118→                                        <VerifiedBadge badge={opinionsData.users.badge} size={14} />
119→                                        <span className="so-dot">·</span>
120→                                        <span className="so-date">{formatPostDate(opinionsData.created_at)}</span>
121→                                    </div>
122→                                    <div className="so-body" onClick={(e) => handleClickContent(e, opinionsData.id, opinionsData.user_id)}>
123→                                        <MentionText text={opinionsData.opinion} />
124→                                    </div>
125→                                    <div className="so-action-row">
126→                                        <span className="so-reply-btn" onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinionsData.id, userId: opinionsData.user_id } }); }}>
127→                                            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
128→                                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
129→                                            </svg>
130→                                            Reply
131→                                        </span>
132→                                    </div>
133→                                </div>
134→                            </div>
135→                        </div>
136→                    ))}
137→                    {hasNextPage && (
138→                        <div onClick={() => handleClickSeeMore()} className='see-fullpage-bttn'>
139→                            See more
140→                        </div>
141→                    )}
142→
143→                </div>
144→            </div>
145→        </div>
146→        </>
147→    )
148→}
149→export default SidebarOpinions;
