  1→import { useInfiniteQuery } from "@tanstack/react-query";
  2→import { useEffect } from "react";
  3→import { useLocation, useNavigate } from "react-router-dom";
  4→import { getUserOpinions } from "../../../API/Api";
  5→import { AnimatePresence, motion } from "framer-motion";
  6→import { useInView } from "react-intersection-observer";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→import { useAuth } from "../../Context/useAuth";
  9→import { handleClickProfile } from "../../../helpers/handleClicks";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→import { MoonLoader } from "react-spinners";
 12→import MentionText from "../mentions/MentionText";
 13→
 14→const cardVariants = {
 15→    hidden: { opacity: 0, y: 12 },
 16→    visible: (i) => ({
 17→        opacity: 1,
 18→        y: 0,
 19→        transition: { duration: 0.3, delay: i * 0.04, ease: "easeOut" }
 20→    })
 21→};
 22→
 23→const VisitedProfileOpinions = () =>{
 24→    const {ref, inView} = useInView({threshold: 0, rootMargin: '200px'})
 25→    const location = useLocation();
 26→    const navigate = useNavigate();
 27→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 28→   const {openAuthModal, session, user} = useAuth();;
 29→
 30→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
 31→        queryKey: ['getUserOpinions', userId],
 32→        queryFn: ({pageParam = null, queryKey}) => getUserOpinions(pageParam, 5, queryKey[1]),
 33→        getNextPageParam: (lastPage) => {
 34→            if(lastPage.hasMore){
 35→                const lastOpinion = lastPage?.data[lastPage?.data.length - 1]
 36→                return lastOpinion.id;
 37→            } else {
 38→                return undefined
 39→            }
 40→        },
 41→        refetchOnWindowFocus: false,
 42→        enabled: !!userId,
 43→        staleTime: 1000 * 60 * 5
 44→    })
 45→
 46→
 47→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
 48→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
 49→        if(!session){
 50→            e.stopPropagation();
 51→            return openAuthModal();
 52→        }
 53→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
 54→    };
 55→
 56→    const handleClickContent = (e, opinionId, userId) =>{
 57→        e.stopPropagation();
 58→        if(!session) return openAuthModal();
 59→        navigate('/home/opinionsViewer', {
 60→            state: {
 61→                opinionId: opinionId,
 62→                userId: userId
 63→            }
 64→        })
 65→    }
 66→
 67→    useEffect(() =>{
 68→        if(inView && hasNextPage && !isFetchingNextPage){
 69→            fetchNextPage();
 70→        }
 71→    },[inView, hasNextPage, isFetchingNextPage, fetchNextPage])
 72→
 73→    const opinions = data?.pages?.flatMap((page) => page.data) || [];
 74→
 75→    if(isLoading){
 76→        return(
 77→            <div className="visited-profile-opinions-container">
 78→                <div className="opinions-loading-container">
 79→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
 80→                </div>
 81→            </div>
 82→        )
 83→    }
 84→
 85→    if(opinions?.length === 0){
 86→        return(
 87→            <div className="visited-profile-opinions-container">
 88→                No opinions available
 89→            </div>
 90→        )
 91→    }
 92→
 93→    return(
 94→        <>
 95→        <AnimatePresence>
 96→        <div className="visited-profile-opinions-container">
 97→            {opinions.map((opinion, index) => (
 98→                <motion.div
 99→                    className="so-card-wrapper"
100→                    key={opinion.id}
101→                    custom={index}
102→                    initial="hidden"
103→                    animate="visible"
104→                    variants={cardVariants}
105→                >
106→                    <div className="so-card">
107→                        <div className="so-card-content">
108→                            <div className="so-header-row">
109→                                <div className={`so-avatar-outer ${opinion.users.badge === 'legend' ? 'avatar-ring-legend' : opinion.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
110→                                    <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, userId)} className="so-avatar" src={opinion.users.image_url || "../../assets/profile.jpg"} alt={`${opinion?.users?.name || "User"} profile picture`} />
111→                                </div>
112→                                <span className="so-username">{opinion.users.name}</span>
113→                                <VerifiedBadge badge={opinion.users.badge} size={14} />
114→                                <span className="so-dot">·</span>
115→                                <span className="so-date">{formatPostDate(opinion.created_at)}</span>
116→                            </div>
117→
118→                            <div
119→                                onClick={(e) => handleClickContent(e, opinion.id, opinion.users.id)}
120→                                className="so-body"
121→                            >
122→                                <MentionText text={opinion.opinion} />
123→                            </div>
124→
125→                            <div className="so-action-row">
126→                                <span className="so-reply-btn" onClick={(e) => { e.stopPropagation(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}>
127→                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
128→                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
129→                                    </svg>
130→                                    {opinion.reply_count || 0} {opinion.reply_count === 1 ? 'reply' : 'replies'}
131→                                </span>
132→                            </div>
133→                        </div>
134→                    </div>
135→                </motion.div>
136→            ))}
137→
138→            <div ref={ref} className="visited-user-opinions-inview">
139→            </div>
140→        </div>
141→        </AnimatePresence>
142→        </>
143→    )
144→}
145→
146→export default VisitedProfileOpinions;
