  1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  2→import { AnimatePresence, motion } from "framer-motion";
  3→import { useEffect, useLayoutEffect, useRef, useState } from "react";
  4→import { useLocation, useNavigate } from "react-router-dom";
  5→import { getOpinions } from "../../../API/Api";
  6→import { useAuth } from "../../Context/useAuth";
  7→import { useInView } from "react-intersection-observer";
  8→import { useMediaQuery } from "react-responsive";
  9→import { handleClickProfile } from "../../../helpers/handleClicks";
 10→import OpinionEditor from "./OpinionsEditor";
 11→import formatPostDate from "../../../helpers/formatDateString";
 12→import VerifiedBadge from "../Badge/VerifiedBadge";
 13→import MentionText from "../mentions/MentionText";
 14→
 15→const cardVariants = {
 16→    hidden: { opacity: 0, y: 12 },
 17→    visible: (i) => ({
 18→        opacity: 1,
 19→        y: 0,
 20→        transition: { duration: 0.3, delay: i * 0.04, ease: "easeOut" }
 21→    })
 22→};
 23→
 24→const OpinionsPage = () =>{
 25→    const [showHeaders, setShowHeaders] = useState(true);
 26→    const [showWriteContainer, setShowWriteContainer] = useState(true);
 27→    const [scrollReady, setScrollReady] = useState(false);
 28→    const {ref, inView} = useInView({threshold: 0.5, rootMargin: '200px'});
 29→
 30→    const isMobile = useMediaQuery({query: '(max-width: 480px'});
 31→
 32→    const timeoutRef = useRef();
 33→    const {user, session, openAuthModal} = useAuth();
 34→    const queryClient = useQueryClient();
 35→
 36→    const [openOpinionEditor, setOpenOpinionEditor] = useState(false);
 37→
 38→    const {isLoading, data, fetchNextPage, isFetchingNextPage, hasNextPage} = useInfiniteQuery({
 39→        queryKey: ['getOpinions'],
 40→        queryFn:({pageParam = null}) => getOpinions(pageParam, 5),
 41→        getNextPageParam: (lastPage) => {
 42→            if(lastPage.hasMore){
 43→                const lastOpinion = lastPage?.data[lastPage?.data.length - 1];
 44→                return lastOpinion.id;
 45→            } else {
 46→                return undefined;
 47→            }
 48→        },
 49→        refetchOnWindowFocus: false,
 50→        staleTime: 1000 * 60 * 5,
 51→    })
 52→
 53→    const links = [
 54→        {label: 'Writings', path: '/home'},
 55→        {label: 'Opinions', path: '/home/opinions'}
 56→    ]
 57→    const location = useLocation();
 58→    const navigate = useNavigate();
 59→
 60→    const handleClickLinks = (path) => {
 61→        navigate(path);
 62→    }
 63→
 64→    const handleClickWriteOpinion = (e) =>{
 65→        e.stopPropagation();
 66→        if(!session) return openAuthModal();
 67→        setOpenOpinionEditor(true)
 68→    }
 69→
 70→    const closeOpinionEditor = () =>{
 71→        setOpenOpinionEditor(false);
 72→    }
 73→
 74→    const handleClickOpinionProfileOriginal = handleClickProfile(navigate);
 75→    const handleClickOpinionProfile = (e, loggedInUserId, clickedUserId) => {
 76→        if(!session){
 77→            e.stopPropagation();
 78→            return openAuthModal();
 79→        }
 80→        handleClickOpinionProfileOriginal(e, loggedInUserId, clickedUserId);
 81→    };
 82→
 83→    const handleClickContent = (e, opinionId, userId) =>{
 84→        e.stopPropagation();
 85→        if(!session) return openAuthModal();
 86→        navigate('/home/opinionsViewer', {
 87→            state: {
 88→                opinionId: opinionId,
 89→                userId: userId
 90→            }
 91→        })
 92→    }
 93→
 94→    useLayoutEffect(() =>{
 95→        const scrollContainer = document.querySelector('.home-parent-container');
 96→        if (scrollContainer) {
 97→            scrollContainer.scrollTop = 0;
 98→        } else {
 99→            window.scrollTo(0, 0);
100→        }
101→    }, [])
102→
103→    useEffect(() =>{
104→        const id = requestAnimationFrame(() => setScrollReady(true));
105→        return () => cancelAnimationFrame(id);
106→    }, [])
107→
108→    useEffect(() =>{
109→        const scroll = () =>{
110→            setShowHeaders(false);
111→            setShowWriteContainer(false)
112→            if(timeoutRef.current){
113→                clearTimeout(timeoutRef.current)
114→            }
115→
116→            timeoutRef.current = setTimeout(() =>{
117→                setShowHeaders(true)
118→                setShowWriteContainer(true)
119→            }, 500)
120→        }
121→        document.addEventListener('scroll', scroll, true)
122→        return () =>{
123→            document.removeEventListener('scroll', scroll)
124→            if(timeoutRef.current){
125→                clearTimeout(timeoutRef.current)
126→            }
127→        }
128→    }, [])
129→
130→    useEffect(() =>{
131→        if(scrollReady && inView && hasNextPage && !isFetchingNextPage){
132→            fetchNextPage();
133→        }
134→    }, [scrollReady, inView, hasNextPage, isFetchingNextPage, fetchNextPage])
135→
136→    const opinions = data?.pages.flatMap((page) => page.data) || [];
137→
138→    const fabButton = showWriteContainer && (
139→        <motion.div
140→            className="write-opinion-fab"
141→            onClick={(e) => handleClickWriteOpinion(e)}
142→            initial={{ opacity: 0, scale: 0.8 }}
143→            animate={{ opacity: 1, scale: 1, transition: { duration: 0.3, ease: 'easeOut' } }}
144→            exit={{ opacity: 0, scale: 0.8, transition: { duration: 0.2, ease: 'easeIn' } }}
145→            whileHover={{ scale: 1.08 }}
146→            whileTap={{ scale: 0.92 }}
147→        >
148→            <svg xmlns="http://www.w3.org/2000/svg" width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
149→                <path d="M12 20h9" />
150→                <path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z" />
151→            </svg>
152→        </motion.div>
153→    );
154→
155→    const headerNav = showHeaders && (
156→        <motion.div
157→            className="newsfeed-header"
158→            initial={{opacity: 0}}
159→            animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
160→            exit={{ opacity: 0, y: -20, transition: { duration: 0.2, ease: "easeOut" } }}
161→        >
162→            {links.map((link, index) =>(
163→                <div onClick={() => handleClickLinks(link.path)} key={index} className='header-link'>
164→                    {link.label}
165→                    <div className={link.path === location.pathname ? "header-underline" : ''}></div>
166→                </div>
167→            ))}
168→        </motion.div>
169→    );
170→
171→    if(opinions.length === 0 && !isLoading) {
172→        return (
173→            <AnimatePresence>
174→            <>
175→                {openOpinionEditor && (
176→                    <OpinionEditor onClose={closeOpinionEditor}/>
177→                )}
178→                {headerNav}
179→                <div className="opinions-page-parent-container">
180→                    {fabButton}
181→                    <div>
182→                        No opinions availabe
183→                    </div>
184→                </div>
185→            </>
186→            </AnimatePresence>
187→        )
188→    }
189→
190→    return(
191→        <AnimatePresence>
192→        <>
193→        {openOpinionEditor && (
194→            <OpinionEditor onClose={closeOpinionEditor}/>
195→        )}
196→        {headerNav}
197→
198→        <div className="opinions-page-parent-container">
199→            {fabButton}
200→
201→            {opinions.map((opinion, index) => (
202→                <motion.div
203→                    key={opinion.id}
204→                    className="so-card-wrapper"
205→                    custom={index}
206→                    initial="hidden"
207→                    animate="visible"
208→                    variants={cardVariants}
209→                >
210→                    <div className="so-card">
211→                        <div className="so-card-content">
212→                            <div className="so-header-row">
213→                                <div className={`so-avatar-outer ${opinion.users.badge === 'legend' ? 'avatar-ring-legend' : opinion.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
214→                                    <img onClick={(e) => handleClickOpinionProfile(e, user?.userData[0].id, opinion.user_id)} className="so-avatar" src={opinion.users.image_url || "../../assets/profile.jpg"} alt={`${opinion?.users?.name || "User"} profile picture`} />
215→                                </div>
216→                                <span onClick={(e) => handleClickOpinionProfile(e, user?.userData[0].id, opinion.user_id)} className="so-username">{opinion.users.name}</span>
217→                                <VerifiedBadge badge={opinion.users.badge} size={14}/>
218→                                <span className="so-dot">·</span>
219→                                <span className="so-date">{formatPostDate(opinion.created_at)}</span>
220→                            </div>
221→                            <div className="so-body" onClick={(e) => handleClickContent(e, opinion.id, opinion.user_id)}>
222→                                <MentionText text={opinion.opinion} />
223→                            </div>
224→                            <div className="so-action-row">
225→                                <motion.button
226→                                    className="so-reply-btn"
227→                                    whileHover={{ scale: 1.04 }}
228→                                    whileTap={{ scale: 0.96 }}
229→                                    onClick={(e) => { e.stopPropagation(); if(!session) return openAuthModal(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}
230→                                >
231→                                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
232→                                        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
233→                                    </svg>
234→                                    Reply
235→                                </motion.button>
236→                            </div>
237→                        </div>
238→                    </div>
239→                </motion.div>
240→            ))}
241→            <div className="opinions-in-view" ref={ref}>
242→            </div>
243→        </div>
244→
245→
246→        </>
247→        </AnimatePresence>
248→    )
249→}
250→
251→export default OpinionsPage;
