  1→import { useInfiniteQuery } from "@tanstack/react-query";
  2→import { useAuth } from "../../Context/useAuth";
  3→import { getMyOpinions } from "../../../API/Api";
  4→import { useEffect } from "react";
  5→import { useNavigate } from "react-router-dom";
  6→import { AnimatePresence, motion } from "framer-motion";
  7→import { useInView } from "react-intersection-observer";
  8→import VerifiedBadge from "../Badge/VerifiedBadge";
  9→import formatPostDate from "../../../helpers/formatDateString";
 10→import { MoonLoader } from "react-spinners";
 11→import MentionText from "../mentions/MentionText";
 12→
 13→const MyOpinions = () =>{
 14→    const {session, user, openAuthModal} = useAuth();
 15→
 16→    const navigate = useNavigate();
 17→    const {ref, inView} = useInView({threshold: 0, rootMargin: '200px'})
 18→
 19→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
 20→        queryKey: ['getMyOpinions', session?.user?.id],
