 26→
 27→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
 28→        queryKey: ['getReplyOpinion', opinionId],
 29→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
 30→        getNextPageParam: (lastPage) => {
 31→            if (lastPage?.hasMore) {
 32→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 33→                return lastReply.id;
 34→            }
 35→            return undefined;
 36→        },
 37→        enabled: !!opinionId,
 38→        refetchOnWindowFocus: false,
 39→        staleTime: 1000 * 60 * 5
