116→                                    <button
117→                                        className="rc-show-replies"
118→                                        onClick={() => setShowReply(prev => !prev)}
119→                                    >
120→                                        {showReply ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
121→                                    </button>
122→                                )}
123→                                <button
124→                                    className="rc-reply-btn"
125→                                    onClick={() => setShowReplyButtonId(
